const TOKEN = '8732835567:AAH6ZqWNPM57nuSY6SybjtlVjJk_vxBcOjk';
const BASE = `https://api.telegram.org/bot${TOKEN}`;
const PROXY = 'https://kokolsk1y.app.n8n.cloud/webhook/tv-video?url=';

function proxyUrl(url) {
  return url ? PROXY + encodeURIComponent(url) : '';
}

// Кэш постов между запросами
const cache = $getWorkflowStaticData('global');
if (!cache.photos) cache.photos = [];
if (!cache.video) cache.video = null;

const updates = $input.first().json.result || [];

// Берём только channel_post, сортируем по message_id (старые → новые)
const channelPosts = updates
  .filter(u => u.channel_post)
  .map(u => u.channel_post)
  .sort((a, b) => a.message_id - b.message_id);

for (const msg of channelPosts) {
  if (msg.photo) {
    // Берём самый большой размер фото
    const largest = msg.photo[msg.photo.length - 1];
    const fileRes = await fetch(`${BASE}/getFile?file_id=${largest.file_id}`);
    const fileJson = await fileRes.json();
    const imgUrl = fileJson.ok
      ? `https://api.telegram.org/file/bot${TOKEN}/${fileJson.result.file_path}`
      : '';
    cache.photos.unshift({
      type: 'photo',
      text: msg.caption || '',
      date: new Date(msg.date * 1000).toISOString(),
      img: proxyUrl(imgUrl),
      msg_id: msg.message_id
    });
    // Оставляем только 2 последних фото
    cache.photos = cache.photos.slice(0, 2);
  }

  if (msg.video) {
    const videoRes = await fetch(`${BASE}/getFile?file_id=${msg.video.file_id}`);
    const videoJson = await videoRes.json();
    const videoUrl = videoJson.ok
      ? `https://api.telegram.org/file/bot${TOKEN}/${videoJson.result.file_path}`
      : '';

    let thumbUrl = '';
    const thumb = msg.video.thumbnail || msg.video.thumb;
    if (thumb) {
      const thumbRes = await fetch(`${BASE}/getFile?file_id=${thumb.file_id}`);
      const thumbJson = await thumbRes.json();
      thumbUrl = thumbJson.ok
        ? `https://api.telegram.org/file/bot${TOKEN}/${thumbJson.result.file_path}`
        : '';
    }

    cache.video = {
      type: 'video',
      text: msg.caption || '',
      date: new Date(msg.date * 1000).toISOString(),
      videoUrl: proxyUrl(videoUrl),
      videoThumb: proxyUrl(thumbUrl),
      msg_id: msg.message_id
    };
  }
}

// Подтверждаем обновления (чтобы не накапливались в очереди)
if (updates.length > 0) {
  const lastId = Math.max(...updates.map(u => u.update_id));
  await fetch(`${BASE}/getUpdates?offset=${lastId + 1}&limit=1`);
}

const posts = [
  ...cache.photos,
  ...(cache.video ? [cache.video] : [])
];

return [{ json: { posts, updatedAt: new Date().toISOString() } }];

